SELECT COUNT(DISTINCT S.PK_SIAPE) AS TOTAL FROM SERVIDOR S JOIN CALC_HORA_AULA_MEDIA C ON C.SIAPE = S.PK_SIAPE WHERE LOWER(S.CONTRATO) = LOWER('efetivos') AND C.ANO = 2022 AND C.SEMESTRE = 2 AND LOWER(C.SIGLA_CAMPUS) = LOWER('gyn') AND LOWER(C.AREA_INGRESSO) LIKE LOWER('%arquitetura%') AND LOWER(C.AREA_INGRESSO) LIKE LOWER('%urbanismo%')